( function( $ ) {

	"use strict";

	// Elementor Editor Popup
	var CrtElementorEditorPopup = {

		loaded: false,

		init: function() {
			window.elementor.on( 'preview:loaded', CrtElementorEditorPopup.loadPreview );
		},

		loadPreview: function() {
			window.elementorFrontend.hooks.addAction( 'frontend/element_ready/crt-offcanvas.default', function( $scope ) {
				$scope.find( '.crt-template-edit-btn' ).on( 'click', CrtElementorEditorPopup.renderPopup );
			} );

			window.elementorFrontend.hooks.addAction( 'frontend/element_ready/crt-elementor-template.default', function( $scope ) {
				$scope.find( '.crt-template-edit-btn' ).on( 'click', CrtElementorEditorPopup.renderPopup );
			} );

			window.elementorFrontend.hooks.addAction( 'frontend/element_ready/shortcode.default', function( $scope ) {
				$scope.find( '.crt-template-edit-btn' ).on( 'click', CrtElementorEditorPopup.renderPopup );
			} );

			window.elementorFrontend.hooks.addAction( 'frontend/element_ready/crt-advanced-slider.default', function( $scope ) {
				$scope.find( '.crt-template-edit-btn' ).on( 'click', CrtElementorEditorPopup.renderPopup );
			} );

			window.elementorFrontend.hooks.addAction( 'frontend/element_ready/crt-tabs.default', function( $scope ) {
				$scope.find( '.crt-template-edit-btn' ).on( 'click', CrtElementorEditorPopup.renderPopup );
			} );

			window.elementorFrontend.hooks.addAction( 'frontend/element_ready/crt-content-toggle.default', function( $scope ) {
				$scope.find( '.crt-template-edit-btn' ).on( 'click', CrtElementorEditorPopup.renderPopup );
			} );

			window.elementorFrontend.hooks.addAction( 'frontend/element_ready/crt-advanced-accordion.default', function( $scope ) {
				$scope.find( '.crt-template-edit-btn' ).on( 'click', CrtElementorEditorPopup.renderPopup );
			} );
		},

		renderPopup: function( link ) {
			// Open Editor
			CrtElementorEditorPopup.getPopup().show();

			// Render Iframe
			$( '#crt-template-editor-popup .dialog-message').html( '<iframe src="' + $( this ).data( 'permalink' ) + '&elementor' + '" id="crt-template-edit-frame" width="100%" height="100%"></iframe>' );
			
			// Preloading
			$( '#crt-template-editor-popup .dialog-message').append( '<div id="crt-template-editor-loading"><div class="elementor-loader-wrapper"><div class="elementor-loader"><div class="elementor-loader-boxes"><div class="elementor-loader-box"></div><div class="elementor-loader-box"></div><div class="elementor-loader-box"></div><div class="elementor-loader-box"></div></div></div><div class="elementor-loading-title">Loading</div></div></div>' );

			// Loaded
			$( '#crt-template-edit-frame').on( 'load', function() {
				$( '#crt-template-editor-loading').fadeOut( 300 );
			} );

			// Close
			$( '#crt-template-editor-popup .dialog-close-button' ).css({
				'right' : '30px',
				'width' : '35px',
				'height' : '35px',
				'line-height' : '30px',
				'border-radius' : '50%',
				'text-align' : 'center',
				'opacity' : '1',
				'background-color' : '#333',
				'box-shadow' : '1px 1px 3px 0 #000',
			}).html('<i class="eicon-close"></i>');

			$( '#crt-template-editor-popup .dialog-close-button i' ).css({
				'font-size' : '15px',
				'color' : '#fff',
			})

			$( '#crt-template-editor-popup .dialog-close-button' ).on( 'click', function() {
				elementor.reloadPreview();
			});
		},

		getPopup: function() {

			if ( ! CrtElementorEditorPopup.loaded ) {
				this.loaded = elementor.dialogsManager.createWidget( 'lightbox', {
					id: 'crt-template-editor-popup',
					closeButton: true,
					hide: { onBackgroundClick: false }
				} );
			}

			return CrtElementorEditorPopup.loaded;
		}

	};

	$( window ).on( 'elementor:init', CrtElementorEditorPopup.init );


	// Modal Popups
	var CrtModalPopups = {

		init: function() {
			if ( ! $( 'body' ).hasClass( 'elementor-editor-crt-popups' ) ) {
				return;
			}

			// Load Preview
			window.elementor.on( 'preview:loaded', CrtModalPopups.onPreviewLoad );

			// Change Preview
			window.elementor.on( 'preview:loaded', CrtModalPopups.onPreviewChange );

			// Change Controls
			elementor.settings.page.model.on( 'change', CrtModalPopups.onControlChange );
		},

		onPreviewLoad: function() {
			// Open Popup Settings
			setTimeout(function() {
				if ( $( '#elementor-panel-footer-settings' ).length ) {
					$( '#elementor-panel-footer-settings' ).trigger( 'click' );
				} else {
					setTimeout(function() {
						$( '#elementor-panel-footer-settings' ).trigger( 'click' );
					}, 5000);
				}
			}, 2000);

			// Popup Settings Notification
			CrtModalPopups.settingsNotification();

			// Fix Popup Layout
			window.elementorFrontend.hooks.addAction( 'frontend/element_ready/global', function( $scope ) {
				var popup = $scope.closest( '.crt-template-popup' );

				CrtModalPopups.fixPopupLayout( popup );
			} );
		},

		onPreviewChange: function() {
			// preview change code goes here
		},

		onControlChange: function( model ) {
			var iframe = document.getElementById( 'elementor-preview-iframe' ),
				iframeContent = iframe.contentDocument || iframe.contentWindow.document;

			// Popup
			var popup = $( '.crt-template-popup', iframeContent );

			// Scrollbar
			if ( model.changed.hasOwnProperty( 'popup_height' ) ) {
				// elementor.reloadPreview();
			}

			// Display As
			if ( model.changed.hasOwnProperty( 'popup_display_as' ) ) {
				if ( 'notification' === model.changed['popup_display_as'] ) {
					popup.addClass( 'crt-popup-notification' );
				} else {
					popup.removeClass( 'crt-popup-notification' );
				}
			}

			if ( model.changed.hasOwnProperty( 'popup_display_as' ) ) {

			}

			// Entrance Animation
			if ( model.changed.hasOwnProperty( 'popup_animation' ) ) {
				var popupContainer = popup.find('.crt-popup-container');

				popupContainer.removeAttr( 'class');
				popupContainer.addClass( 'crt-popup-container animated '+ model.changed['popup_animation'] );
			}
		},

		fixPopupLayout: function( popup ) {
			var settings = CrtModalPopups.getDocumentSettings();

			// Add Scrollbar
			if ( ! popup.find('.crt-popup-container-inner').hasClass('ps') ) {
				const ps = new PerfectScrollbar(popup.find('.crt-popup-container-inner')[0], {
					suppressScrollX: true
				});
			}

			if ( 'notification' === settings.popup_display_as ) {
				popup.addClass( 'crt-popup-notification' );
			}
		},

		getDocumentSettings: function() {
			var documentSettings = {},
				settings = elementor.settings.page.model;

			jQuery.each(settings.getActiveControls(), function (controlKey) {
				documentSettings[controlKey] = settings.attributes[controlKey];
			});

			return documentSettings;
		},

		settingsNotification: function() {
			var version = $('#crt-addons-editor-js-js').attr('src');
				version = 'v-'+ version.substring(version .length - 6, version .length);

			// Get Close Time
			var closeTime = JSON.parse( localStorage.getItem( 'CrtPopupEditorNotification'+ version) ) || {};

			if ( closeTime + 604800000 >= Date.now() ) {
				return;
			}

			// Notification HTML
			if ( $('body').find('#elementor-editor-wrapper-v2').length > 0 ) {
				// Notification HTML
				var nHTML = '\
					<div id="crt-template-settings-notification" class="crt-new-editor-bar">\
						<h4><i class="eicon-info-circle"></i><span>Please Note</span></h4>\
						<p>Click here to access <strong>Popup Settings</strong>.<br>Click our Logo to the bottom to open a <strong>Popup Library</strong>.</p>\
						<i class="eicon-close"></i>\
					</div>\
				';
			} else {
				var nHTML = '\
				<div id="crt-template-settings-notification">\
					<h4><i class="eicon-info-circle"></i><span>Please Note</span></h4>\
					<p>Click here to access <strong>Popup Settings</strong>.<br>Click our Logo to the right to open a <strong>Popup Library</strong>.</p>\
					<i class="eicon-close"></i>\
				</div>\
			';
			}

			// Render Notification
			if ( $('body').find('#elementor-editor-wrapper-v2').length > 0 ) {
				$('body .MuiBox-root button[value="document-settings"]').append(nHTML).hide().fadeIn();
			} else {
				$( 'body' ).append( nHTML ).hide().fadeIn();
			}

			// Hide on Click
			$( '#crt-template-settings-notification .eicon-close' ).on( 'click', function() {
				$( '#crt-template-settings-notification' ).fadeOut();

				// Save Close Time in Browser
				localStorage.setItem( 'CrtPopupEditorNotification'+ version, Date.now() );
			});
		},
	};

	$( window ).on( 'elementor:init', CrtModalPopups.init );


	// Theme Builder
	var CrtThemeBuilder = {

		init: function() {
			if ( ! $( 'body' ).hasClass( 'elementor-editor-crt-theme-builder' ) ) {
				return;
			}

			// Load Preview
			window.elementor.on( 'preview:loaded', CrtThemeBuilder.onPreviewLoad );
		},

		onPreviewLoad: function() {

			// Popup Settings Notification
			CrtThemeBuilder.settingsNotification();

			// Submit Preview Changes
			$( '#elementor-panel-footer-settings' ).on( 'click', function() {
				setTimeout(function() {
					$( '.elementor-control-submit_preview_changes button' ).on( 'click', function() {
						$e.run('document/save/auto', {
						force: true,
							onSuccess: function onSuccess() {
								elementor.reloadPreview();
								elementor.once('preview:loaded', function () {
									$e.route('panel/page-settings/settings');
								});
							}
						});
					});
				}, 500);
			});

		},

		settingsNotification: function() {
			var version = $('#crt-addons-editor-js-js').attr('src');
				version = 'v-'+ version.substring(version .length - 6, version .length);

			// Get Close Time
			var closeTime = JSON.parse( localStorage.getItem('CrtThemeBuilderNotification'+ version) ) || {};

			if ( closeTime + 604800000 >= Date.now() ) {
				return;
			}

			if ( $('body').find('#elementor-editor-wrapper-v2').length > 0 ) {
				// Notification HTML
				var nHTML = '\
					<div id="crt-template-settings-notification" class="crt-new-editor-bar">\
						<h4><i class="eicon-info-circle"></i><span>Please Note</span></h4>\
						<p>You can change <strong>Preview Settings</strong> here.</p>\
						<i class="eicon-close"></i>\
					</div>\
				';
			} else {
				// Notification HTML
				var nHTML = '\
					<div id="crt-template-settings-notification">\
						<h4><i class="eicon-info-circle"></i><span>Please Note</span></h4>\
						<p>You can change <strong>Preview Settings</strong> here.</p>\
						<i class="eicon-close"></i>\
					</div>\
				';
			}

			setTimeout(function() {
				// Render Notification
				if ( !$('#crt-template-settings-notification').length ) {
					if ( $('body').find('#elementor-editor-wrapper-v2').length > 0 ) {
						$('body .MuiBox-root button[value="document-settings"]').append(nHTML).hide().fadeIn();
					} else {
						$('body').append(nHTML).hide().fadeIn();
					}

					// Set Close Time
					$(document).on( 'click', function() {
						$('#crt-template-settings-notification').fadeOut();
					});

					// Hide on Click
					$('#crt-template-settings-notification .eicon-close').on( 'click', function() {
						$( '#crt-template-settings-notification' ).fadeOut();

						// Save Close Time in Browser
						localStorage.setItem( 'CrtThemeBuilderNotification'+ version, Date.now() );
					});
				}
			}, 1000 );
		},
	};

	$( window ).on( 'elementor:init', CrtThemeBuilder.init );
    
    // Sticky Section Editor JS
    $(window).on('elementor:init', function () {
		elementor.settings.page.addChangeCallback( 'crt_rpb_enable', function ( newValue ) {
            if('yes' == newValue ) {
                let wrpbHtml = '<div class="crt-reading-progress-bar-container"><div class="crt-reading-progress-bar crt-mybar" id="crt-mybar"></div></div>';
                $( elementorFrontend.elements.$body ).append( wrpbHtml );
            } else {
                if ( $( elementorFrontend.elements.$body ).find( '.crt-reading-progress-bar-container' ).length ) {
                    $( elementorFrontend.elements.$body ).find( '.crt-reading-progress-bar-container' ).remove();
                }
            }
        });
	});

	$(window).on('elementor:init', function () {
		// Data Table
		elementor.hooks.addAction( 'panel/open_editor/widget/crt-data-table', function( panel, model, view ) {
			elementor.channels.editor.on( 'my-table-export',() => {
				
				console.log('table exporting');
				// var html = view.$el.find('.crt-data-table');
				var html = view.$el.find('.crt-data-table').prop('outerHTML');
				htmlToCSV(html, "placeholder.csv", view);
			} );
		});
	});

	function htmlToCSV(html, filename, view) {
		var data = [];
		var rows = view.$el.find('.crt-data-table').find(".crt-table-row");
				
		for (var i = 0; i < rows.length; i++) {
			var row = [], cols = rows[i].querySelectorAll(".crt-table-text");
					
			for (var j = 0; j < cols.length; j++) {
					row.push(cols[j].innerText);
			}
			
			data.push(row.join(",")); 		
		}
	
		downloadCSVFile(data.join("\n"), filename);
	}

	function downloadCSVFile(csv, filename) {
		var csv_file, download_link;
	
		csv_file = new Blob([csv], {type: "text/csv"});
	
		download_link = document.createElement("a");
	
		download_link.download = filename;
	
		download_link.href = window.URL.createObjectURL(csv_file);
	
		download_link.style.display = "none";
	
		document.body.appendChild(download_link);
	
		download_link.click();
	} // Data Table CSV export

}( jQuery ) );

function connectInstagramInit(obj) {

    if (!obj) return;

    var type = jQuery(obj).data("type");

	console.log(type);

    connectInstagram(obj, type);
}

